#include<bits/stdc++.h>
using namespace std;
int n,c,siz;
multiset<int> a,b;
int best(int x,int op)
{
    if(x==-1)
    {
        return -1;
    }
    auto it=a.upper_bound(c-1-x);
    if(it==a.begin())
    {
        return -1;
    }
    it--;
    if(op==1&&(*it)==x&&a.count(x)==1)
    {
        return (it==a.begin()?-1:(*(--it)));
    }
    return *it;
}
void insert(int x)
{
    siz++;
    if(siz==1)
    {
        a.insert(x);
        return;
    }
    int y=best(x,0),z=best(y,1),w=best(z,1);
    if(y!=-1&&z<x)
    {
        if(z!=-1&&y==w)
        {
            b.erase(b.find(y+z));
        }
        b.insert(x+y);
    }
    a.insert(x);
}
void erase(int x)
{
    a.erase(a.find(x));
    siz--;
    if(siz==0)
    {
        return;
    }
    int y=best(x,0),z=best(y,1),w=best(z,1);
    if(y!=-1&&z<x)
    {
        if(z!=-1&&y==w)
        {
            b.insert(y+z);
        }
        b.erase(b.find(x+y));
    }
}
int query()
{
    auto it=(--a.end());
    if(a.count(*it)>=2)
    {
        return (*it)*2%c;
    }
    else
    {
        return ((*it)+(*(--it)))%c;
    }
}
int main()
{
    scanf("%d%d",&n,&c);
    int lstans=0;
    while(n--)
    {
        int op,x;
        scanf("%d%d",&op,&x);
        x^=lstans;
        if(op==1)
        {
            insert(x%c);
        }
        else if(op==2)
        {
            erase(x%c);
        }
        if(siz<2)
        {
            printf("EE\n");
            lstans=0;
            continue;
        }
        int ans=(b.empty()?0:(*b.rbegin()));
        ans=max(ans,query());
        printf("%d\n",lstans=ans);
    }
    return 0;
}
